package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

/**
 * Tests for deprecated SharedFlow.toList() and SharedFlow.toSet() methods with destination parameter.
 * These tests verify that the destination parameter is properly passed through to the underlying Flow methods.
 */
class SharedFlowToListTest : TestBase() {

    @Test
    fun testToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val destination = mutableListOf<Int>()

        // Launch a coroutine that collects into the destination list
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(destination)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        // Give the collector time to receive the values
        yield()

        // Cancel the collection
        job.cancel()

        // Verify the destination list was populated
        assertEquals(listOf(1, 2, 3), destination)
    }

    @Test
    fun testToListWithPrePopulatedDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val destination = mutableListOf(100, 200) // Pre-populated list

        // Launch a coroutine that collects into the destination list
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(destination)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        // Give the collector time to receive the values
        yield()

        // Cancel the collection
        job.cancel()

        // Verify the destination list contains both pre-existing and new values
        assertEquals(listOf(100, 200, 1, 2), destination)
    }

    @Test
    fun testToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val destination = mutableSetOf<Int>()

        // Launch a coroutine that collects into the destination set
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(destination)
        }

        // Emit some values (including duplicates)
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(1) // duplicate
        sharedFlow.emit(3)

        // Give the collector time to receive the values
        yield()

        // Cancel the collection
        job.cancel()

        // Verify the destination set was populated (without duplicates)
        assertEquals(setOf(1, 2, 3), destination)
    }

    @Test
    fun testToSetWithPrePopulatedDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val destination = mutableSetOf(100, 200) // Pre-populated set

        // Launch a coroutine that collects into the destination set
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toSet(destination)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(200) // duplicate of pre-existing value

        // Give the collector time to receive the values
        yield()

        // Cancel the collection
        job.cancel()

        // Verify the destination set contains both pre-existing and new values
        assertEquals(setOf(100, 200, 1, 2), destination)
    }

    @Test
    fun testToListEmptyFlow() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val destination = mutableListOf<Int>()

        // Launch a coroutine that collects into the destination list
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION")
            sharedFlow.toList(destination)
        }

        // Don't emit any values, just wait a bit
        yield()

        // Cancel the collection
        job.cancel()

        // Verify the destination list remains empty
        assertTrue(destination.isEmpty())
    }
}
"}

